CREATE TABLE "square_connections" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL,"organization_id" uuid NOT NULL REFERENCES "organizations"("id"),"store_id" uuid NOT NULL REFERENCES "stores"("id"),"merchant_id" text NOT NULL,"location_id" text NOT NULL,"device_id" text,"access_token_encrypted" text NOT NULL,"refresh_token_encrypted" text,"token_expires_at" timestamp with time zone,"status" "status" DEFAULT 'active' NOT NULL,"created_at" timestamp with time zone DEFAULT now() NOT NULL,"updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE UNIQUE INDEX "square_connection_store_uq" ON "square_connections" ("store_id");
CREATE UNIQUE INDEX "square_connection_merchant_location_uq" ON "square_connections" ("merchant_id","location_id");
CREATE TABLE "square_oauth_states" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL,"organization_id" uuid NOT NULL REFERENCES "organizations"("id"),"store_id" uuid NOT NULL REFERENCES "stores"("id"),"user_id" uuid NOT NULL REFERENCES "users"("id"),"token_hash" text NOT NULL,"expires_at" timestamp with time zone NOT NULL,"used_at" timestamp with time zone,"created_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE UNIQUE INDEX "square_oauth_state_hash_uq" ON "square_oauth_states" ("token_hash");
